## Example Code Structure:

### **App.tsx** (Entry Point)
```typescript
import { NavigationContainer } from '@react-navigation/native';
import AppNavigator from './navigation/AppNavigator';
import { AppStateProvider } from './state/AppStateManager';

export default function App() {
  return (
    <AppStateProvider>
      <NavigationContainer>
        <AppNavigator />
      </NavigationContainer>
    </AppStateProvider>
  );
}
```

